div.script:
document.addEventListener("DOMContentLoaded", function() {
    // 1. Lógica del Contador Regresivo
    const fechaExamenStr = "";
    let targetDate = new Date(fechaExamenStr).getTime();
    if (isNaN(targetDate)) {
        targetDate = new Date(fechaExamenStr + "Z").getTime();
    }

    const countdownInterval = setInterval(function() {
        const now = new Date().getTime();
        const distance = targetDate - now;

        if (distance <= 0) {
            clearInterval(countdownInterval);
            document.getElementById("countdown").innerHTML = "¡TIEMPO CUMPLIDO!";
            document.getElementById("countdown").classList.replace("text-danger", "text-success");
            document.getElementById("btn_iniciar").classList.remove("d-none");
            document.getElementById("txt_espera").classList.add("d-none");
            activarAntiFraude(); // Activar seguridad al iniciar
        } else {
            const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((distance % (1000 * 60)) / 1000);

            document.getElementById("countdown").innerHTML = 
                (hours < 10 ? "0" : "") + hours + ":" + 
                (minutes < 10 ? "0" : "") + minutes + ":" + 
                (seconds < 10 ? "0" : "") + seconds;
        }
    }, 1000);

    // 2. Lógica Anti-Fraude (Vigilancia del Foco de la Pestaña)
    let advertencias = 0;
    function activarAntiFraude() {
        document.addEventListener("visibilitychange", function() {
            if (document.hidden) {
                advertencias++;
                alert("ADVERTENCIA #" + advertencias + ": No tienes permitido salir de la pestaña del examen. Esta acción quedará registrada.");
                if (advertencias >= 3) {
                    alert("Has superado el límite de advertencias permitidas. Tu examen será cerrado.");
                    // Redirección para cerrar el examen si ya está dentro
                    window.location.href = "/survey/submit"; 
                }
            }
        });
    }
});

xpath.script:
document.addEventListener("DOMContentLoaded", function() {
    // Escuchar a nivel global los clics en el botón 'Enviar' dentro del modal de confirmación final de Odoo
    document.addEventListener("click", function(ev) {
        const btn = ev.target.closest('button');
        if (!btn) return;

        // Verificar si el botón está dentro del cuadro de diálogo (pop-up modal) de confirmación final
        const isModal = btn.closest('.modal, .o_dialog, .modal-dialog');
        if (isModal && (btn.classList.contains('btn-primary') || btn.classList.contains('o_confirm'))) {
            const overlay = document.getElementById('survey_ia_loading_overlay');
            if (overlay) overlay.classList.remove('d-none');
        }
    });

    // Observar cambios en el DOM para ocultar el spinner en cuanto Odoo complete la petición AJAX y cargue la pantalla final
    const wrap = document.getElementById('wrapwrap');
    if (wrap) {
        const observer = new MutationObserver(function(mutations) {
            // Verificar si apareció la pantalla de encuesta finalizada o si desapareció el formulario
            const isFinished = document.querySelector('.o_survey_finished, .o_survey_completed');
            const formExists = document.querySelector('form');
            if (isFinished || !formExists) {
                const overlay = document.getElementById('survey_ia_loading_overlay');
                if (overlay && !overlay.classList.contains('d-none')) {
                    overlay.classList.add('d-none');
                }
            }
        });
        observer.observe(wrap, { childList: true, subtree: true });
    }
});

document.addEventListener("DOMContentLoaded", function() {
    function checkFormSubmits() {
        const forms = document.querySelectorAll('form, form[action*="/website_form/"]');
        forms.forEach(form => {
            form.addEventListener('submit', function() {
                document.getElementById('cv_ia_loading_overlay').classList.remove('d-none');
            });
        });

        const submitBtns = document.querySelectorAll('.o_website_form_send, button[type="submit"]');
        submitBtns.forEach(btn => {
            btn.addEventListener('click', function() {
                const form = this.closest('form');
                if (!form || form.checkValidity()) {
                    document.getElementById('cv_ia_loading_overlay').classList.remove('d-none');
                }
            });
        });
    }

    checkFormSubmits();
});
